import React, { useEffect, useState } from 'react';

function App() {
    const [projects, setProjects] = useState([]);
    const [newName, setNewName] = useState('');

    // 1. Projekte laden
    const fetchProjects = () => {
        fetch('http://localhost:8081/api/projects')
        .then(res => res.json())
        .then(data => setProjects(data));
    };

    useEffect(() => { fetchProjects(); }, []);

    // 2. Projekt hinzufügen
    const addProject = (e) => {
        e.preventDefault();
        fetch('http://localhost:8081/api/projects', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name: newName, status: 'OPEN', description: 'Neu angelegt' })
        }).then(() => {
            setNewName('');
            fetchProjects();
        });
    };

    // 3. Projekt löschen
    const deleteProject = (id) => {
        fetch(`http://localhost:8081/api/projects/${id}`, { method: 'DELETE' })
        .then(() => fetchProjects());
    };

    return (
        <div style={{ padding: '40px', maxWidth: '600px', margin: '0 auto', fontFamily: 'Arial' }}>
        <h1>🛠️ IT-Service Task Manager</h1>

        {/* Formular zum Hinzufügen */}
        <form onSubmit={addProject} style={{ marginBottom: '20px' }}>
        <input
        value={newName}
        onChange={(e) => setNewName(e.target.value)}
        placeholder="Neues Projekt benennen..."
        style={{ padding: '8px', width: '70%' }}
        />
        <button type="submit" style={{ padding: '8px', marginLeft: '10px', cursor: 'pointer' }}>Hinzufügen</button>
        </form>

        {/* Liste der Projekte */}
        <ul style={{ listStyle: 'none', padding: 0 }}>
        {projects.map(p => (
            <li key={p.id} style={{ background: '#f4f4f4', marginBottom: '10px', padding: '15px', borderRadius: '5px', display: 'flex', justifyContent: 'space-between' }}>
            <span><strong>{p.name}</strong> ({p.status})</span>
            <button onClick={() => deleteProject(p.id)} style={{ color: 'red', border: 'none', background: 'none', cursor: 'pointer' }}>Löschen</button>
            </li>
        ))}
        </ul>
        </div>
    );
}

export default App;
